// 1. Loop 노드에서 ID와 이름을 모두 참조
const propertyId = $('Loop Over Items').item.json.propertyId;
const propertyName = $('Loop Over Items').item.json.propertyName; // 이 줄을 추가합니다.

// 2. 데이터 가공 (기존 로직 유지)
const historyData = items
  .map(item => ({
    date: [
      item.json.date.slice(0, 4),
      item.json.date.slice(4, 6),
      item.json.date.slice(6, 8)
    ].join('-'),
    sessions: parseFloat(item.json.sessions)
  }))
  .sort((a, b) => a.date.localeCompare(b.date));

const targetDate = historyData[historyData.length - 1].date;

// 3. property_name을 포함하여 리턴 (API 규격 준수)
return [{
  json: {
    property_id: propertyId,
    property_name: propertyName, // 필드 추가
    target_date: targetDate,
    history_data: historyData
  }
}];

// 리팩토링된 Code in JavaScript2 (컨텍스트 인덱스 동기화 완료)

// 1. 현재 루프 회차에서 처리 중인 데이터(보통 10개)만 가져옵니다.
const loopItems = $('Loop Over Items').all(); 

const results = items.map((item, index) => {
    // 2. [교정] n8n 컨텍스트 내에서는 index(0~9)가 loopItems와 1:1로 정확히 매칭됩니다.
    // globalIndex 계산식은 가차 없이 삭제합니다.
    const propertyId = loopItems[index].json.propertyId;
    const propertyName = loopItems[index].json.propertyName;

    // 3. HTTP Request 노드 응답 파싱
    const reports = item.json.reports || [];
    const rows = (reports[0] && reports[0].rows) ? reports[0].rows : [];

    const historyData = rows.map(row => ({
        date: [
            row.dimensionValues[0].value.slice(0, 4),
            row.dimensionValues[0].value.slice(4, 6),
            row.dimensionValues[0].value.slice(6, 8)
        ].join('-'),
        sessions: parseFloat(row.metricValues[0].value)
    })).sort((a, b) => a.date.localeCompare(b.date));

    const targetDate = historyData.length > 0 ? historyData[historyData.length - 1].date : "";

    return {
        property_id: propertyId,
        property_name: propertyName,
        target_date: targetDate,
        history_data: historyData
    };
});

// 백엔드 전송 규격 포장
return [{
    json: {
        batch_size: results.length,
        properties: results
    }
}];

// 1. GA4 응답 결과 전체를 가져옵니다.
const inputItems = $input.all();
const dataList = [];

for (const item of inputItems) {
    const report = item.json.reports && item.json.reports[0];
    const rows = (report && report.rows) || [];

    // 2. 프로퍼티 정보 참조 (Context Mapping)
    let propertyId = "unknown";
    let propertyName = "unknown";

    try {
        // 원본 노드 'Code in JavaScript4'의 데이터를 현재 인덱스에 맞춰 가져옵니다.
        const source = $("Code in JavaScript4").item.json;
        propertyId = source.propertyId || "unknown";
        propertyName = source.propertyName || "unknown";
    } catch (e) {
        console.error("Context mapping failed:", e);
    }

    const channelMap = {};

    // 3. 데이터를 채널별로 그룹화 (백엔드가 기대하는 구조)
    rows.forEach(row => {
        const dateStr = [
            row.dimensionValues[0].value.slice(0, 4),
            row.dimensionValues[0].value.slice(4, 6),
            row.dimensionValues[0].value.slice(6, 8)
        ].join('-');

        const channel = row.dimensionValues[1].value;
        const sessions = parseFloat(row.metricValues[0].value);

        if (!channelMap[channel]) channelMap[channel] = [];

        channelMap[channel].push({
            date: dateStr,
            sessions: sessions
        });
    });

    // 4. 마지막 날짜 추출
    const targetDate = rows.length > 0 ? [
        rows[rows.length - 1].dimensionValues[0].value.slice(0, 4),
        rows[rows.length - 1].dimensionValues[0].value.slice(4, 6),
        rows[rows.length - 1].dimensionValues[0].value.slice(6, 8)
    ].join('-') : "";

    // [중요] 백엔드 필수 필드명인 'grouped_channels'로 데이터 포장
    dataList.push({
        property_id: propertyId,
        property_name: propertyName,
        target_date: targetDate,
        grouped_channels: channelMap 
    });
}

// 5. 전체 배치 포장
return [{
    json: {
        total_count: dataList.length,
        data: dataList
    }
}];

// JS Node 1: 이상 징후 필터링 및 평탄화(Flattening)
const allBatches = items; // 9개의 배치 묶음
const anomalyProperties = [];

allBatches.forEach(batch => {
    const results = batch.json.results || [];
    results.forEach(res => {
        if (res.is_anomaly === true) {
            const propertyId = res.property_id;
            anomalyProperties.push({
                json: {
                    property_id: propertyId,
                    propertyId,
                    propertyName: res.property_name
                }
            });
        }
    });
});

return anomalyProperties;

// 1. 타겟 계정 ID 및 제외 설정
const targetAccountId = "101423321";
const excludedProperties = [
    "properties/338476357", "properties/405383368", "properties/396589406", 
    "properties/389068544", "properties/396587111", "properties/396596928",
    "properties/396611752", "properties/399792463", "properties/404766492", 
    "properties/404770191", "properties/404777182", "properties/404783166",
    "properties/405913800", "properties/405921879", "properties/244753299", 
    "properties/290653701", "properties/357136492", "properties/433447824",
    "properties/359782962", "properties/441817328", "properties/429284171", 
    "properties/436477471", "properties/486365237", "properties/486431162",
    "properties/489666261", "properties/493901606", "properties/510907920", 
    "properties/517283074", "properties/492787484"
];

const results = [];
const summaries = items[0].json.accountSummaries || [];

for (const accountSummary of summaries) {
  const currentAccountId = accountSummary.account.split('/')[1];
  if (currentAccountId !== targetAccountId) continue;

  if (accountSummary.propertySummaries) {
    for (const property of accountSummary.propertySummaries) {
      const propertyPath = property.property;
      const displayName = property.displayName;
      const propertyId = propertyPath.split('/')[1];

      if (excludedProperties.includes(propertyPath)) continue;
      if (displayName.toLowerCase().includes('subproperty')) continue;

      results.push({
        json: {
          accountId: currentAccountId,
          property_id: propertyId,
          propertyId,
          propertyName: displayName
        }
      });
    }
  }
}

return results;

// Build ecommerce detection targets from the incoming property list.
// Keep sessions workflow untouched; this branch prepares generic single-metric tasks.
const targetEvents = ["view_item", "add_to_cart", "begin_checkout", "purchase"];
const properties = $input.all();

return properties
  .map(item => {
    const propertyId = item.json.property_id || item.json.propertyId;
    return {
      json: {
        property_id: propertyId,
        propertyId,
        propertyName: item.json.propertyName,
        targetEvents,
      }
    };
  })
  .filter(item => item.json.property_id);

const loopItems = $('Loop Ecommerce Detection').all();

return items.map((item, index) => {
  const source = loopItems[index].json;
  const propertyId = source.property_id || source.propertyId;
  const reports = item.json.reports || [];
  const rows = reports[0]?.rows || [];

  const series = rows.map(row => ({
    date: [
      row.dimensionValues[0].value.slice(0, 4),
      row.dimensionValues[0].value.slice(4, 6),
      row.dimensionValues[0].value.slice(6, 8),
    ].join('-'),
    value: parseFloat(row.metricValues[0].value || '0'),
  })).sort((a, b) => a.date.localeCompare(b.date));

  return {
    json: {
      domain: 'ecommerce',
      mode: 'detection',
      property_id: propertyId,
      property_name: source.propertyName,
      metric_name: 'eventCount',
      dimensions: {},
      target_date: series.length ? series[series.length - 1].date : undefined,
      target_events: source.targetEvents,
      series,
    }
  };
}).filter(item => item.json.property_id && item.json.series.length >= 2);

const anomalyProperties = [];

for (const item of items) {
  if (item.json.is_anomaly !== true) continue;

  const result = item.json.result || {};
  const nextAction = item.json.next_action || {};
  const propertyId = result.property_id || nextAction.property_id || item.json.property_id || item.json.propertyId;
  if (!propertyId) continue;

  anomalyProperties.push({
    json: {
      property_id: propertyId,
      propertyId,
      propertyName: result.property_name || item.json.property_name || propertyId,
      metricName: result.metric_name || nextAction.metric_name || 'eventCount',
      targetEvents: nextAction.target_events || [],
    }
  });
}

return anomalyProperties;

const source = $('Loop Ecommerce Diagnosis').item.json;
const propertyId = source.property_id || source.propertyId;
const report = items[0].json.reports?.[0] || {};
const rows = report.rows || [];
const byEvent = {};

for (const row of rows) {
  const date = [
    row.dimensionValues[0].value.slice(0, 4),
    row.dimensionValues[0].value.slice(4, 6),
    row.dimensionValues[0].value.slice(6, 8),
  ].join('-');
  const eventName = row.dimensionValues[1].value;
  const value = parseFloat(row.metricValues[0].value || '0');

  if (!byEvent[eventName]) byEvent[eventName] = [];
  byEvent[eventName].push({ date, value });
}

return Object.entries(byEvent)
  .map(([eventName, series]) => ({
    json: {
      domain: 'ecommerce',
      mode: 'diagnosis',
      property_id: propertyId,
      property_name: source.propertyName,
      metric_name: source.metricName || 'eventCount',
      dimensions: { eventName },
      target_date: series.length ? series[series.length - 1].date : undefined,
      series: series.sort((a, b) => a.date.localeCompare(b.date)),
    }
  }))
  .filter(item => item.json.property_id && item.json.series.length >= 2);

// Prepare properties for the Unassigned Traffic branch without changing other branches.
const properties = $input.all();

return properties
  .map(item => {
    const propertyId = item.json.property_id || item.json.propertyId;
    return {
      json: {
        property_id: propertyId,
        propertyId,
        propertyName: item.json.propertyName,
        accountId: item.json.accountId,
      },
    };
  })
  .filter(item => item.json.property_id);

const source = $('Loop Unassigned Detection').item.json;
const propertyId = source.property_id || source.propertyId;
const report = items[0].json.reports?.[0] || {};
const rows = report.rows || [];

const payloadRows = rows.map(row => ({
  date: row.dimensionValues[0]?.value,
  sessionDefaultChannelGroup: row.dimensionValues[1]?.value,
  sessions: parseFloat(row.metricValues[0]?.value || '0'),
})).filter(row => row.date);

if (!propertyId || payloadRows.length === 0) return [];

const sortedDates = [...new Set(payloadRows.map(row => row.date))].sort();

return [{
  json: {
    property_id: propertyId,
    property_name: source.propertyName,
    corporation: source.accountId,
    date_start: sortedDates[0],
    date_end: sortedDates[sortedDates.length - 1],
    target_date: sortedDates[sortedDates.length - 1],
    rows: payloadRows,
  },
}];

const diagnosisTargets = [];

for (const item of items) {
  if (item.json.should_run_diagnosis !== true) continue;

  const result = item.json.result || {};
  const metadata = result.metadata || {};
  const propertyId = item.json.property_id || result.property_id;
  if (!propertyId) continue;

  diagnosisTargets.push({
    json: {
      property_id: propertyId,
      propertyId,
      propertyName: item.json.property_name || result.property_name || propertyId,
      corporation: item.json.corporation || metadata.corporation,
      targetDate: item.json.target_date || result.target_date,
      groupKey: item.json.group_key || metadata.group_key,
    },
  });
}

return diagnosisTargets;

const source = $('Loop Unassigned Diagnosis').item.json;
const propertyId = source.property_id || source.propertyId;
const report = items[0].json.reports?.[0] || {};
const rows = report.rows || [];

const payloadRows = rows.map(row => ({
  date: row.dimensionValues[0]?.value,
  sessionSourceMedium: row.dimensionValues[1]?.value,
  sessions: parseFloat(row.metricValues[0]?.value || '0'),
})).filter(row => row.date);

if (!propertyId || payloadRows.length === 0) return [];

const sortedDates = [...new Set(payloadRows.map(row => row.date))].sort();

return [{
  json: {
    property_id: propertyId,
    property_name: source.propertyName,
    corporation: source.corporation,
    target_date: source.targetDate || sortedDates[sortedDates.length - 1],
    date_start: sortedDates[0],
    date_end: sortedDates[sortedDates.length - 1],
    parent_group_key: source.groupKey,
    rows: payloadRows,
  },
}];
